import { describe, it, expect, beforeAll } from 'vitest'
import { api, uniqueEmail } from './setup.js'

describe('Article Routes', () => {
  let adminToken: string
  let userToken: string
  let userRefreshToken: string
  const testEmail = uniqueEmail()
  const testPassword = 'TestPass123!'
  const slug = `test-article-${Date.now()}`
  let articleId: string

  beforeAll(async () => {
    // Login as admin
    const adminRes = await api('POST', '/api/auth/login', {
      email: 'admin@maiy.tech',
      password: 'maiy2026',
    })
    adminToken = adminRes.data.accessToken

    // Register and login as regular user
    const userRes = await api('POST', '/api/auth/register', {
      email: testEmail,
      password: testPassword,
      name: 'Article Tester',
    })
    userToken = userRes.data.accessToken
    userRefreshToken = userRes.data.refreshToken
  })

  describe('GET /api/articles', () => {
    it('returns article list with pagination', async () => {
      const { status, data } = await api('GET', '/api/articles')

      expect(status).toBe(200)
      expect(data.articles).toBeDefined()
      expect(Array.isArray(data.articles)).toBe(true)
      expect(data.pagination).toBeDefined()
      expect(data.pagination.page).toBeDefined()
      expect(data.pagination.total).toBeDefined()
    })

    it('supports pagination params', async () => {
      const { status, data } = await api('GET', '/api/articles?page=1&limit=5')

      expect(status).toBe(200)
      expect(data.pagination.limit).toBe(5)
    })

    it('supports category filter', async () => {
      const { status, data } = await api('GET', '/api/articles?category=AI')

      expect(status).toBe(200)
      data.articles.forEach((a: any) => {
        // Only published articles returned
      })
    })
  })

  describe('POST /api/articles (admin)', () => {
    it('creates an article as admin', async () => {
      const { status, data } = await api(
        'POST',
        '/api/articles',
        {
          slug,
          title: 'Test Article',
          excerpt: 'A test article excerpt',
          content: 'Full article content here...',
          category: 'AI',
          tags: ['test', 'ai'],
          readingTime: 5,
        },
        { Authorization: `Bearer ${adminToken}` }
      )

      expect(status).toBe(201)
      expect(data.slug).toBe(slug)
      expect(data.title).toBe('Test Article')
      expect(data.category).toBe('AI')
      expect(data.tags).toContain('test')
      articleId = data.id
    })

    it('rejects article creation without auth', async () => {
      const { status, data } = await api('POST', '/api/articles', {
        slug: 'another-slug',
        title: 'No Auth Article',
        content: 'Content',
        category: 'WEB_DEV',
        tags: [],
      })

      expect(status).toBe(401)
    })

    it('rejects article creation as non-admin', async () => {
      const { status, data } = await api(
        'POST',
        '/api/articles',
        {
          slug: `user-article-${Date.now()}`,
          title: 'User Article',
          content: 'Content',
          category: 'WEB_DEV',
          tags: [],
        },
        { Authorization: `Bearer ${userToken}` }
      )

      expect(status).toBe(403)
      expect(data.error).toBe('Admin only')
    })

    it('fails with missing required fields', async () => {
      const { status } = await api(
        'POST',
        '/api/articles',
        { title: 'Missing Slug' },
        { Authorization: `Bearer ${adminToken}` }
      )

      expect(status).toBe(400)
    })

    it('fails with invalid category', async () => {
      const { status } = await api(
        'POST',
        '/api/articles',
        {
          slug: `invalid-cat-${Date.now()}`,
          title: 'Invalid Category',
          content: 'Content',
          category: 'INVALID_CAT',
          tags: [],
        },
        { Authorization: `Bearer ${adminToken}` }
      )

      expect(status).toBe(400)
    })
  })

  describe('GET /api/articles/:slug', () => {
    it('gets article by slug', async () => {
      const { status, data } = await api('GET', `/api/articles/${slug}`)

      expect(status).toBe(200)
      expect(data.slug).toBe(slug)
      expect(data.author).toBeDefined()
    })

    it('returns 404 for non-existent slug', async () => {
      const { status } = await api('GET', '/api/articles/does-not-exist-xyz')

      expect(status).toBe(404)
    })
  })

  describe('PUT /api/articles/:id (admin)', () => {
    it('updates article as admin', async () => {
      const { status, data } = await api(
        'PUT',
        `/api/articles/${articleId}`,
        {
          title: 'Updated Test Article',
          excerpt: 'Updated excerpt',
        },
        { Authorization: `Bearer ${adminToken}` }
      )

      expect(status).toBe(200)
      expect(data.title).toBe('Updated Test Article')
      expect(data.excerpt).toBe('Updated excerpt')
    })

    it('rejects update as non-admin', async () => {
      const { status } = await api(
        'PUT',
        `/api/articles/${articleId}`,
        { title: 'Hacked Title' },
        { Authorization: `Bearer ${userToken}` }
      )

      expect(status).toBe(403)
    })
  })

  describe('PATCH /api/articles/:id/publish (admin)', () => {
    it('publishes article', async () => {
      const { status, data } = await api(
        'PATCH',
        `/api/articles/${articleId}/publish`,
        { published: true },
        { Authorization: `Bearer ${adminToken}` }
      )

      expect(status).toBe(200)
      expect(data.published).toBe(true)
    })

    it('unpublishes article', async () => {
      const { status, data } = await api(
        'PATCH',
        `/api/articles/${articleId}/publish`,
        { published: false },
        { Authorization: `Bearer ${adminToken}` }
      )

      expect(status).toBe(200)
      expect(data.published).toBe(false)
    })
  })

  describe('DELETE /api/articles/:id (admin)', () => {
    it('deletes article as admin', async () => {
      const { status } = await api(
        'DELETE',
        `/api/articles/${articleId}`,
        undefined,
        { Authorization: `Bearer ${adminToken}` }
      )

      expect(status).toBe(200)
    })

    it('returns 404 after deletion', async () => {
      const { status } = await api('GET', `/api/articles/${slug}`)

      expect(status).toBe(404)
    })

    it('rejects delete as non-admin', async () => {
      // Create article first
      const create = await api(
        'POST',
        '/api/articles',
        {
          slug: `delete-test-${Date.now()}`,
          title: 'Delete Test',
          content: 'Content',
          category: 'WEB_DEV',
          tags: [],
        },
        { Authorization: `Bearer ${adminToken}` }
      )

      const { status } = await api(
        'DELETE',
        `/api/articles/${create.data.id}`,
        undefined,
        { Authorization: `Bearer ${userToken}` }
      )

      expect(status).toBe(403)
    })
  })
})

