// Global error handler — return 400 for Zod validation errors
app.setErrorHandler((error, request, reply) => {
  if (error instanceof error.constructor && error.name === 'ZodError') {
    return reply.status(400).send({ error: 'Validation failed', details: (error as any).issues })
  }
  if (error.validation) {
    return reply.status(400).send({ error: 'Validation failed', details: error.validation })
  }
  request.log.error(error)
  return reply.status(error.statusCode ?? 500).send({ error: error.message ?? 'Internal Server Error' })
})

