describe('POST /api/auth/login', () => {
    it('logs in with valid credentials', async () => {
      const { status, data } = await api('POST', '/api/auth/login', {
        email: testEmail,
        password: testPassword,
      })

      expect(status).toBe(200)
      expect(data.user).toBeDefined()
      expect(data.user.email).toBe(testEmail)
      expect(data.accessToken).toBeDefined()
      expect(data.refreshToken).toBeDefined()
      // Re-capture token from login (login rotates tokens, invalidating the register token)
      testUserRefreshToken = data.refreshToken
    })

    it('fails with wrong password', async () => {
      const { status, data } = await api('POST', '/api/auth/login', {
        email: testEmail,
        password: 'WrongPassword123!',
      })

      expect(status).toBe(401)
      expect(data.error).toBe('Invalid credentials')
    })

    it('fails with non-existent email', async () => {
      const { status, data } = await api('POST', '/api/auth/login', {
        email: 'nobody@maiy.tech',
        password: testPassword,
      })

      expect(status).toBe(401)
      expect(data.error).toBe('Invalid credentials')
    })
  })

  describe('POST /api/auth/refresh', () => {
    it('refreshes token with valid refresh token', async () => {
      const { status, data } = await api('POST', '/api/auth/refresh', {
        refreshToken: testUserRefreshToken,
      })

      expect(status).toBe(200)
      expect(data.accessToken).toBeDefined()
    })

