# ============================================================
# MAIY Tech Hub Backend — Nginx Config (Production)
# Place at: /etc/nginx/sites-available/maiy-backend
# Then: sudo ln -s /etc/nginx/sites-available/maiy-backend /etc/nginx/sites-enabled/
# ============================================================

upstream maiy_backend {
    server 127.0.0.1:4000;
    keepalive 64;
}

server {
    listen 80;
    server_name api.maiy.tech;  # <-- Update with your domain

    # Redirect HTTP to HTTPS (uncomment after SSL setup)
    # return 301 https://$server_name$request_uri;

    client_max_body_size 500M;  # Allow large uploads (Cloudinary uploads)

    access_log /var/log/nginx/maiy-backend-access.log;
    error_log  /var/log/nginx/maiy-backend-error.log;

    location / {
        proxy_pass http://maiy_backend;
        proxy_http_version 1.1;

        # Headers
        proxy_set_header Host              $host;
        proxy_set_header X-Real-IP         $remote_addr;
        proxy_set_header X-Forwarded-For    $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Connection         "";

        # Timeouts
        proxy_connect_timeout 60s;
        proxy_send_timeout    60s;
        proxy_read_timeout    60s;

        # Buffering
        proxy_buffering    on;
        proxy_buffer_size  4k;
        proxy_buffers      8 4k;
    }

    # Health check endpoint — don't rate limit
    location /health {
        proxy_pass http://maiy_backend;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        access_log off;
    }
}

