import { FastifyPluginAsync } from 'fastify'
import fp from 'fastify-plugin'
import mongoose from 'mongoose'
import { config } from '../config/index.js'

declare module 'fastify' {
  interface FastifyInstance {
    mongo: typeof mongoose
  }
}

const mongodbPlugin: FastifyPluginAsync = async (fastify) => {
  const mongoUri = config.MONGODB_URL

  try {
    await mongoose.connect(mongoUri)
    fastify.log.info('✅ Connected to MongoDB')
  } catch (err) {
    fastify.log.error('❌ MongoDB connection failed:', err)
    throw err
  }

  fastify.decorate('mongo', mongoose)

  fastify.addHook('onClose', async () => {
    await mongoose.disconnect()
    fastify.log.info('🔌 MongoDB disconnected')
  })
}

export default fp(mongodbPlugin, { name: 'mongodb' })

